   182	func (s *Store) History(metricID string) ([]HistoryRecord, error) {
   183		if s.execStore == nil {
   184			return []HistoryRecord{}, fmt.Errorf("metric store is not initialized")
   185		}
   186		records, err := s.execStore.History(metricID, "")
   187		if err != nil {
   188			return nil, err
   189		}
   190		out := make([]HistoryRecord, 0, len(records))
   191		for _, rec := range records {
   192			mapped, err := metricHistoryFromExec(rec)
   193			if err != nil {
   194				return nil, err
   195			}
   196			if mapped.MetricID == metricID {
   197				out = append(out, mapped)
   198			}
   199		}
   200		return out, nil
   201	}
   202	
   203	func (s *Store) loadMetricArtifact(metricID string) (*docgraph.Document, error) {
   204		if !strings.HasPrefix(metricID, "MET-") {
   205			return nil, fmt.Errorf("%w: %s", errNotMetricArtifact, metricID)
   206		}
   207		graph, err := docgraph.BuildGraph(s.WorkingDir)
   208		if err != nil {
   209			return nil, err
   210		}
   211		doc, ok := graph.Show(metricID)
   212		if !ok {
   213			return nil, fmt.Errorf("metric artifact %q not found", metricID)
   214		}
   215		return &doc, nil
   216	}
   217	
   218	func selectComparisonTarget(history []HistoryRecord, against string) (HistoryRecord, error) {
   219		switch against {
   220		case "", "latest":
   221			return history[len(history)-1], nil
   222		case "baseline":
   223			return history[0], nil
   224		default:
   225			for _, rec := range history {
   226				if rec.RunID == against {
   227					return rec, nil
   228				}
   229			}
   230			return HistoryRecord{}, fmt.Errorf("comparison target %q not found", against)
   231		}
   232	}
   233	
   234	func comparisonFor(current, baseline float64, direction string) ComparisonResult {
   235		delta := current - baseline
   236		if direction == ComparisonHigherIsBetter {
   237			delta = baseline - current
   238		}
   239		return ComparisonResult{
   240			Baseline:  baseline,
   241			Delta:     delta,
   242			Direction: direction,
   243		}
   244	}
   245	
   246	func singleHistoryUnit(metricID string, history []HistoryRecord) (string, error) {
   247		var (
   248			unit    string
   249			seenSet = map[string]struct{}{}
   250			seen    []string
   251		)
   252		for _, rec := range history {
   253			if _, ok := seenSet[rec.Unit]; ok {
   254				continue
   255			}
   256			seenSet[rec.Unit] = struct{}{}
   257			seen = append(seen, rec.Unit)
   258			if len(seen) == 1 {
   259				unit = rec.Unit
   260			}
   261		}
   262		if len(seen) <= 1 {
   263			return unit, nil
   264		}
   265		units := make([]string, 0, len(seen))
   266		for _, v := range seen {
   267			if v == "" {
   268				units = append(units, "(none)")
   269				continue
   270			}
   271			units = append(units, v)
   272		}
   273		return "", fmt.Errorf("metric %q has mixed units: %s", metricID, strings.Join(units, ", "))
   274	}
   275	
   276	func groupHistoryByUnit(history []HistoryRecord) []HistoryGroup {
   277		if len(history) == 0 {
   278			return []HistoryGroup{}
   279		}
   280		indexByUnit := make(map[string]int, len(history))
   281		groups := make([]HistoryGroup, 0, len(history))
   282		for _, rec := range history {
   283			idx, ok := indexByUnit[rec.Unit]
   284			if !ok {
   285				idx = len(groups)
   286				indexByUnit[rec.Unit] = idx
   287				groups = append(groups, HistoryGroup{Unit: rec.Unit})
   288			}
   289			groups[idx].Records = append(groups[idx].Records, rec)
   290		}
   291		return groups
   292	}

